import React, { ReactNode } from "react";
import { red, black } from "../../../../../../assets/colors";
import "./stepContainer.css";

export type StepData = {
  step: number;
  title: string;
};

type StepProps = {
  data: StepData;
  children?: ReactNode;
};

export const StepContainer = (props: StepProps) => {
  const { data, children } = props;
  return (
    <div
    // style={{
    //   width: "98vw",
    //   height: 300,
    //   padding: "1em",
    //   display: "flex",
    //   flexDirection: "row",
    //   alignItems: "flex-start",
    //   borderRadius: "3vw",
    //   borderWidth: "0.1vw",
    //   borderColor: "black",
    //   borderStyle: "solid",
    //   margin: "1vh",
    // }}
    >
      <div style={{ display: "flex", flexDirection: "row" }}>
        <div
          style={{
            backgroundColor: red,
            borderRadius: "3em",
            color: "#fff",
            padding: "0.8em",
            display: "block",
            fontWeight: "bold",
            fontSize: 14,
          }}
        >{`Step ${data.step}`}</div>
        <div
          style={{
            // backgroundColor: black,
            borderRadius: "3em",
            color: black,
            padding: "0.8em",
            display: "block",
            fontWeight: "bold",
            fontSize: 18,
          }}
        >
          {data.title}
        </div>
      </div>
      <div className="StepContent">{children}</div>
    </div>
  );
};

export const StepBlue = (props: StepProps) => {
  const { data, children } = props;
  return (
    <div className="Step">
      <div className="StepTitleRow">
        <div className="StepLabelBlue">{`Step ${data.step}`}</div>
        <div className="StepTitle">{data.title}</div>
      </div>
      <div className="StepContent">{children}</div>
    </div>
  );
};

export const StepGrey = (props: StepProps) => {
  const { data, children } = props;
  return (
    <div className="Step">
      <div className="StepTitleRow">
        <div className="StepLabelGrey">{`Step ${data.step}`}</div>
        <div className="StepTitle">{data.title}</div>
      </div>
      <div className="StepContent">{children}</div>
    </div>
  );
};
